<!DOCTYPE html>
<html lang="id">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>SiBantuDes — BLT-DD Kelurahan Ngerong</title>
    @vite(['resources/css/app.css', 'resources/js/app.js'])
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;500;600;700;800;900&display=swap" rel="stylesheet">
    <style>
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        :root {
            --blue:   #2563eb;
            --blue-d: #1d4ed8;
            --blue-l: #eff6ff;
            --ink:    #0f172a;
            --ink-2:  #334155;
            --muted:  #64748b;
            --faint:  #94a3b8;
            --border: #e2e8f0;
            --surf:   #f8fafc;
        }
        html { scroll-behavior: smooth; }
        body {
            font-family: 'Plus Jakarta Sans', sans-serif;
            background: #f1f5f9;
            color: var(--ink);
            min-height: 100vh;
            -webkit-font-smoothing: antialiased;
        }

        /* ── Navbar ── */
        .nav {
            position: sticky; top: 0; z-index: 200;
            background: rgba(255,255,255,.9);
            backdrop-filter: blur(16px);
            border-bottom: 1px solid var(--border);
        }
        .nav-inner {
            max-width: 1100px; margin: 0 auto;
            padding: 0 20px; height: 56px;
            display: flex; align-items: center; justify-content: space-between;
        }
        .nav-brand { display:flex; align-items:center; gap:10px; text-decoration:none; }
        .nav-logo {
            width:34px; height:34px;
            background: linear-gradient(135deg,#3b82f6,#1d4ed8);
            border-radius:10px; display:flex; align-items:center; justify-content:center;
            font-size:15px; font-weight:900; color:#fff;
            box-shadow: 0 4px 12px rgba(37,99,235,.3);
        }
        .nav-name { font-size:15px; font-weight:800; color:var(--ink); letter-spacing:-.02em; }
        .nav-name span { color:var(--blue); }
        .nav-links { display:flex; gap:6px; align-items:center; flex-wrap:wrap; }
        .nav-link {
            font-size:13px; font-weight:600; color:var(--muted);
            text-decoration:none; padding:7px 14px; border-radius:10px;
            transition: background .15s, color .15s;
            white-space: nowrap;
        }
        .nav-link:hover { background:var(--blue-l); color:var(--blue); }
        .nav-link.active {
            background: linear-gradient(135deg,#3b82f6,#2563eb);
            color:#fff; box-shadow:0 4px 12px rgba(37,99,235,.25);
        }
        @media(max-width:540px){
            .nav-link { padding:6px 10px; font-size:12px; }
        }

        /* ── Hero Carousel ── */
        .hero-carousel {
            position: relative;
            overflow: hidden;
            height: clamp(320px, 55vw, 560px);
        }
        .slide {
            position: absolute; inset: 0;
            opacity: 0; transition: opacity .8s ease;
            pointer-events: none;
        }
        .slide.active { opacity: 1; pointer-events: auto; }
        .slide-img {
            width:100%; height:100%; object-fit:cover;
        }
        .slide-overlay {
            position: absolute; inset: 0;
            background: linear-gradient(
                to right,
                rgba(15,23,42,.72) 0%,
                rgba(15,23,42,.45) 50%,
                rgba(15,23,42,.15) 100%
            );
        }
        .slide-content {
            position: absolute; inset: 0;
            display: flex; flex-direction: column; justify-content: flex-end;
            padding: clamp(20px,4vw,52px) clamp(20px,5vw,64px);
            z-index: 2;
        }
        .slide-badge {
            display: inline-flex; align-items: center; gap:6px;
            background: rgba(255,255,255,.12); border:1px solid rgba(255,255,255,.2);
            backdrop-filter: blur(6px);
            color: #fff; font-size:11px; font-weight:700;
            padding:4px 11px; border-radius:20px;
            margin-bottom:14px; width:fit-content;
            letter-spacing:.04em; text-transform:uppercase;
        }
        .slide-badge-dot {
            width:6px; height:6px; border-radius:50%;
            background:#60a5fa; animation: pulse 2s infinite;
        }
        @keyframes pulse {
            0%,100% { opacity:1; transform:scale(1); }
            50%      { opacity:.5; transform:scale(.85); }
        }
        .slide-title {
            font-size: clamp(22px,4vw,42px);
            font-weight: 900; color:#fff;
            line-height: 1.15; letter-spacing:-.04em;
            margin-bottom:10px; max-width:580px;
        }
        .slide-title .accent { color:#93c5fd; }
        .slide-sub {
            font-size: clamp(13px,1.5vw,16px);
            color:rgba(255,255,255,.75); font-weight:500;
            max-width:460px; line-height:1.6; margin-bottom:22px;
        }
        .slide-actions { display:flex; gap:10px; flex-wrap:wrap; }
        .btn-primary {
            display:inline-flex; align-items:center; gap:8px;
            padding:11px 22px;
            background: linear-gradient(135deg,#3b82f6,#2563eb);
            color:#fff; font-size:13.5px; font-weight:700;
            border-radius:13px; text-decoration:none;
            box-shadow:0 4px 16px rgba(37,99,235,.45);
            transition:transform .15s, box-shadow .15s;
            font-family:inherit; border:none; cursor:pointer;
        }
        .btn-primary:hover { transform:translateY(-2px); box-shadow:0 8px 24px rgba(37,99,235,.5); }
        .btn-primary svg { width:15px; height:15px; }
        .btn-outline {
            display:inline-flex; align-items:center; gap:8px;
            padding:11px 20px;
            background:rgba(255,255,255,.12); border:1.5px solid rgba(255,255,255,.3);
            color:#fff; font-size:13.5px; font-weight:700;
            border-radius:13px; text-decoration:none;
            backdrop-filter:blur(4px);
            transition:background .15s, border-color .15s;
        }
        .btn-outline:hover { background:rgba(255,255,255,.2); border-color:rgba(255,255,255,.5); }
        .btn-outline svg { width:15px; height:15px; }

        /* Carousel controls */
        .car-prev, .car-next {
            position:absolute; top:50%; transform:translateY(-50%);
            z-index:10; background:rgba(255,255,255,.15);
            border:1.5px solid rgba(255,255,255,.25);
            backdrop-filter:blur(6px);
            width:40px; height:40px; border-radius:50%;
            display:flex; align-items:center; justify-content:center;
            cursor:pointer; transition:background .15s;
            color:#fff;
        }
        .car-prev { left:16px; }
        .car-next { right:16px; }
        .car-prev:hover, .car-next:hover { background:rgba(255,255,255,.28); }
        .car-prev svg, .car-next svg { width:18px; height:18px; }

        /* Dots */
        .car-dots {
            position:absolute; bottom:16px; left:50%; transform:translateX(-50%);
            display:flex; gap:7px; z-index:10;
        }
        .car-dot {
            width:7px; height:7px; border-radius:50%;
            background:rgba(255,255,255,.4); border:none; cursor:pointer;
            padding:0; transition:background .2s, transform .2s;
        }
        .car-dot.active { background:#fff; transform:scale(1.3); }

        /* Caption bar */
        .caption-bar {
            background:#fff; border-bottom:1px solid var(--border);
            padding:10px 20px;
        }
        .caption-inner {
            max-width:1100px; margin:0 auto;
            display:flex; align-items:center; gap:10px;
        }
        .caption-icon {
            width:28px; height:28px; border-radius:7px; background:var(--blue-l);
            display:flex; align-items:center; justify-content:center; flex-shrink:0;
        }
        .caption-icon svg { width:13px; height:13px; stroke:var(--blue); }
        .caption-txt { font-size:12.5px; font-weight:700; color:var(--ink); }
        .caption-sub { font-size:11px; color:var(--faint); font-weight:500; margin-top:1px; }

        /* ── Page body ── */
        .page-body {
            max-width:1100px; margin:0 auto;
            padding:32px 20px 60px;
            display:flex; flex-direction:column; gap:24px;
        }

        /* Card */
        .card {
            background:#fff; border-radius:22px;
            border:1.5px solid var(--border);
            box-shadow:0 2px 10px rgba(0,0,0,.04);
            overflow:hidden;
        }
        .card-hd { padding:18px 22px 16px; border-bottom:1px solid #f1f5f9; }
        .card-hd-label { font-size:10.5px; font-weight:800; color:var(--blue); text-transform:uppercase; letter-spacing:.07em; margin-bottom:3px; }
        .card-hd-title { font-size:17px; font-weight:800; color:var(--ink); letter-spacing:-.02em; }
        .card-hd-sub   { font-size:12px; color:var(--faint); margin-top:3px; font-weight:500; }
        .card-body { padding:20px 22px; }

        /* ── Gallery ── */
        .gal-grid {
            display:grid;
            grid-template-columns: repeat(3,1fr);
            gap:10px;
        }
        @media(max-width:700px) { .gal-grid { grid-template-columns:repeat(2,1fr); } }
        @media(max-width:420px) { .gal-grid { grid-template-columns:1fr; } }
        .gal-item {
            position:relative; border-radius:14px; overflow:hidden;
            aspect-ratio:4/3; cursor:pointer;
            border:1.5px solid var(--border);
            transition:transform .2s, box-shadow .2s;
        }
        .gal-item:hover { transform:translateY(-3px); box-shadow:0 8px 24px rgba(0,0,0,.15); }
        .gal-item img { width:100%; height:100%; object-fit:cover; display:block; transition:transform .4s; }
        .gal-item:hover img { transform:scale(1.05); }
        .gal-overlay {
            position:absolute; inset:0;
            background:linear-gradient(to top, rgba(15,23,42,.7) 0%, transparent 55%);
            display:flex; align-items:flex-end; padding:10px 12px;
            opacity:0; transition:opacity .2s;
        }
        .gal-item:hover .gal-overlay { opacity:1; }
        .gal-label { font-size:12px; font-weight:700; color:#fff; }

        /* ── Lightbox ── */
        .lb-backdrop {
            display:none; position:fixed; inset:0; z-index:500;
            background:rgba(0,0,0,.88); backdrop-filter:blur(6px);
            align-items:center; justify-content:center;
        }
        .lb-backdrop.open { display:flex; }
        .lb-wrap {
            position:relative; max-width:880px; width:90vw;
            animation: fadeUp .25s ease;
        }
        @keyframes fadeUp { from { opacity:0; transform:translateY(16px); } to { opacity:1; transform:translateY(0); } }
        .lb-img { width:100%; border-radius:16px; display:block; }
        .lb-cap {
            text-align:center; margin-top:14px;
            font-size:14px; font-weight:700; color:#fff;
        }
        .lb-sub { font-size:12px; color:rgba(255,255,255,.6); margin-top:3px; }
        .lb-close {
            position:absolute; top:-14px; right:-14px;
            width:36px; height:36px; border-radius:50%;
            background:rgba(255,255,255,.15); border:1.5px solid rgba(255,255,255,.25);
            color:#fff; cursor:pointer; display:flex; align-items:center; justify-content:center;
            font-size:18px; line-height:1;
        }
        .lb-prev, .lb-next {
            position:absolute; top:50%; transform:translateY(-50%);
            background:rgba(255,255,255,.12); border:1.5px solid rgba(255,255,255,.2);
            color:#fff; cursor:pointer; width:38px; height:38px;
            border-radius:50%; display:flex; align-items:center; justify-content:center;
            transition:background .15s;
        }
        .lb-prev { left:-50px; }
        .lb-next { right:-50px; }
        .lb-prev:hover, .lb-next:hover { background:rgba(255,255,255,.25); }
        .lb-prev svg, .lb-next svg { width:18px; height:18px; }
        @media(max-width:700px) {
            .lb-prev { left:6px; } .lb-next { right:6px; }
        }

        /* ── Search ── */
        .search-row { display:flex; gap:10px; flex-wrap:wrap; }
        .search-wrap { flex:1; position:relative; min-width:200px; }
        .search-icon { position:absolute; left:13px; top:50%; transform:translateY(-50%); width:16px; height:16px; color:var(--faint); pointer-events:none; }
        .search-input {
            width:100%; padding:12px 15px 12px 40px;
            border:1.5px solid var(--border); border-radius:13px;
            font-size:13.5px; font-family:inherit; color:var(--ink);
            background:var(--surf); outline:none;
            transition:border-color .15s, box-shadow .15s;
        }
        .search-input:focus { border-color:#93c5fd; box-shadow:0 0 0 3px rgba(37,99,235,.1); background:#fff; }
        .search-input::placeholder { color:var(--faint); }
        .search-btn {
            padding:12px 20px; border:none; border-radius:13px;
            background:linear-gradient(135deg,#3b82f6,#2563eb);
            color:#fff; font-size:13.5px; font-weight:700; font-family:inherit;
            cursor:pointer; box-shadow:0 3px 12px rgba(37,99,235,.3);
            transition:transform .12s; white-space:nowrap;
        }
        .search-btn:hover { transform:translateY(-1px); }

        /* Result */
        .result-box { margin-top:16px; border-radius:16px; border:1.5px solid var(--border); overflow:hidden; }
        .result-hero { padding:16px 18px; background:linear-gradient(135deg,#1e40af,#2563eb); display:flex; align-items:center; gap:12px; }
        .result-av { width:44px; height:44px; border-radius:12px; background:rgba(255,255,255,.2); display:flex; align-items:center; justify-content:center; font-size:19px; font-weight:900; color:#fff; flex-shrink:0; border:1.5px solid rgba(255,255,255,.25); }
        .result-name { font-size:14px; font-weight:800; color:#fff; }
        .result-nik  { font-size:10.5px; color:rgba(255,255,255,.7); margin-top:2px; font-family:monospace; }
        .result-grid { display:grid; grid-template-columns:1fr 1fr; background:var(--surf); }
        @media(max-width:480px){ .result-grid{ grid-template-columns:1fr; } }
        .result-field { padding:12px 16px; border-bottom:1px solid #f1f5f9; border-right:1px solid #f1f5f9; }
        .result-field:nth-child(even){ border-right:none; }
        .result-field:nth-last-child(-n+2){ border-bottom:none; }
        .rf-lbl { font-size:9.5px; font-weight:700; color:var(--faint); text-transform:uppercase; letter-spacing:.06em; margin-bottom:3px; }
        .rf-val { font-size:13px; font-weight:700; color:var(--ink); }
        .result-footer { padding:13px 16px; background:#fff; border-top:1px solid #f1f5f9; }
        .pill { display:inline-flex; align-items:center; gap:5px; padding:5px 12px; border-radius:20px; font-size:12px; font-weight:700; }
        .pill-dot { width:6px; height:6px; border-radius:50%; flex-shrink:0; }
        .pill-green { background:#f0fdf4; color:#166534; border:1px solid #bbf7d0; }
        .pill-red   { background:#fff1f2; color:#be123c; border:1px solid #fecdd3; }
        .pill-amber { background:#fffbeb; color:#b45309; border:1px solid #fde68a; }
        .not-found { margin-top:16px; padding:14px 16px; border-radius:13px; background:#fff1f2; border:1.5px solid #fecdd3; display:flex; align-items:center; gap:9px; font-size:13px; font-weight:600; color:#be123c; }
        .not-found svg { width:17px; height:17px; flex-shrink:0; }

        /* Docs */
        .doc-list { display:flex; flex-direction:column; gap:10px; }
        .doc-item { display:flex; align-items:center; justify-content:space-between; gap:12px; padding:13px 15px; border-radius:13px; border:1.5px solid var(--border); background:var(--surf); transition:border-color .15s, background .15s; }
        .doc-item:hover { border-color:#93c5fd; background:var(--blue-l); }
        .doc-icon { width:36px; height:36px; border-radius:9px; background:#fff1f2; display:flex; align-items:center; justify-content:center; flex-shrink:0; border:1px solid #fecdd3; }
        .doc-icon svg { width:17px; height:17px; color:#dc2626; }
        .doc-info { flex:1; min-width:0; }
        .doc-title { font-size:13px; font-weight:700; color:var(--ink); white-space:nowrap; overflow:hidden; text-overflow:ellipsis; }
        .doc-meta  { font-size:10.5px; color:var(--faint); margin-top:2px; }
        .btn-pdf { display:inline-flex; align-items:center; gap:6px; padding:7px 14px; background:#dc2626; color:#fff; font-size:12px; font-weight:700; border-radius:9px; text-decoration:none; flex-shrink:0; box-shadow:0 3px 10px rgba(220,38,38,.25); transition:transform .12s; white-space:nowrap; }
        .btn-pdf:hover { transform:translateY(-1px); }
        .btn-pdf svg { width:12px; height:12px; }
        .empty { text-align:center; padding:36px 16px; }
        .empty-icon { width:46px; height:46px; background:var(--surf); border-radius:50%; display:flex; align-items:center; justify-content:center; margin:0 auto 10px; border:1.5px solid var(--border); }
        .empty-icon svg { width:20px; height:20px; color:var(--faint); }
        .empty p { font-size:13px; font-weight:600; color:var(--faint); }

        /* Footer */
        .footer { border-top:1px solid var(--border); background:#fff; padding:18px 20px; text-align:center; font-size:12px; color:var(--faint); font-weight:500; }
        .footer strong { color:var(--ink-2); }
    </style>
</head>
