<!-- ── LIGHTBOX ── -->
<div class="lb-backdrop" id="lightbox" onclick="closeLbOutside(event)">
    <div class="lb-wrap">
        <button class="lb-close" onclick="closeLightbox()">&times;</button>
        <button class="lb-prev" onclick="lbNav(-1)"><svg fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15 19l-7-7 7-7"/></svg></button>
        <button class="lb-next" onclick="lbNav(1)"><svg fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 5l7 7-7 7"/></svg></button>
        <img id="lbImg" class="lb-img" src="" alt="">
        <div class="lb-cap" id="lbCap"></div>
        <div class="lb-sub" id="lbSub"></div>
    </div>
</div>

<script>
const slides = [
    { img: "data:image/png;base64,", title: "Kantor Desa Ngerong", sub: "Pusat pelayanan masyarakat Desa Ngerong" },
    { img: "data:image/png;base64,", title: "Gedung Desa Ngerong", sub: "Pembangunan fasilitas desa yang terus berkembang" },
    { img: "data:image/png;base64,", title: "Balai Desa Ngerong", sub: "Balai desa dengan arsitektur khas Jawa" },
    { img: "data:image/png;base64,", title: "Penyaluran BLT-DD 2023", sub: "Penyaluran Bantuan Langsung Tunai Dana Desa tahun 2023" },
    { img: "data:image/png;base64,", title: "Musyawarah Penerima BLT-DD 2024", sub: "Rapat penyaluran BLT-DD bersama warga Desa Ngerong" },
    { img: "data:image/png;base64,", title: "Serah Terima BLT-DD 2024", sub: "Penerimaan BLT Dana Desa Rp 300.000 per penerima" },
];
let cur = 0, lbCur = 0, timer;

// ── Build carousel ──
const carousel = document.getElementById('heroCarousel');
slides.forEach((s, i) => {
    const el = document.createElement('div');
    el.className = 'slide' + (i === 0 ? ' active' : '');
    el.innerHTML = `
        <img class="slide-img" src="${s.img}" alt="${s.title}">
        <div class="slide-overlay"></div>
        <div class="slide-content">
            <div class="slide-badge"><span class="slide-badge-dot"></span>Desa Ngerong</div>
            <div class="slide-title">${i === 0 ? 'Sistem Informasi<br><span class=\\"accent\\">BLT Dana Desa</span><br>Kelurahan Ngerong' : s.title}</div>
            <div class="slide-sub">${i === 0 ? 'Portal informasi publik untuk mengecek status pengajuan bantuan secara transparan dan akuntabel.' : s.sub}</div>
            ${i === 0 ? `<div class="slide-actions">
                <a href="#cek-status" class="btn-primary"><svg fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/></svg>Cek Status</a>
                <a href="#hasil-publik" class="btn-outline"><svg fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>Laporan Publik</a>
            </div>` : ''}
        </div>`;
    carousel.appendChild(el);
});

// Prev/next buttons
const prevBtn = document.createElement('button');
prevBtn.className = 'car-prev';
prevBtn.innerHTML = '<svg fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15 19l-7-7 7-7"/></svg>';
prevBtn.onclick = () => goTo(cur - 1);
carousel.appendChild(prevBtn);

const nextBtn = document.createElement('button');
nextBtn.className = 'car-next';
nextBtn.innerHTML = '<svg fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 5l7 7-7 7"/></svg>';
nextBtn.onclick = () => goTo(cur + 1);
carousel.appendChild(nextBtn);

// Dots
const dotsWrap = document.createElement('div');
dotsWrap.className = 'car-dots';
slides.forEach((_, i) => {
    const d = document.createElement('button');
    d.className = 'car-dot' + (i === 0 ? ' active' : '');
    d.onclick = () => goTo(i);
    dotsWrap.appendChild(d);
});
carousel.appendChild(dotsWrap);

function goTo(n) {
    const allSlides = carousel.querySelectorAll('.slide');
    const dots = dotsWrap.querySelectorAll('.car-dot');
    allSlides[cur].classList.remove('active');
    dots[cur].classList.remove('active');
    cur = (n + slides.length) % slides.length;
    allSlides[cur].classList.add('active');
    dots[cur].classList.add('active');
    document.getElementById('captionTxt').textContent = slides[cur].title;
    document.getElementById('captionSub').textContent = slides[cur].sub;
    resetTimer();
}

function resetTimer() {
    clearInterval(timer);
    timer = setInterval(() => goTo(cur + 1), 5000);
}
resetTimer();

// ── Lightbox ──
function openLightbox(i) {
    lbCur = i;
    updateLb();
    document.getElementById('lightbox').classList.add('open');
    document.body.style.overflow = 'hidden';
}
function closeLightbox() {
    document.getElementById('lightbox').classList.remove('open');
    document.body.style.overflow = '';
}
function closeLbOutside(e) {
    if (e.target === document.getElementById('lightbox')) closeLightbox();
}
function lbNav(dir) {
    lbCur = (lbCur + dir + slides.length) % slides.length;
    updateLb();
}
function updateLb() {
    document.getElementById('lbImg').src = slides[lbCur].img;
    document.getElementById('lbCap').textContent = slides[lbCur].title;
    document.getElementById('lbSub').textContent = slides[lbCur].sub;
}
document.addEventListener('keydown', e => {
    if (!document.getElementById('lightbox').classList.contains('open')) return;
    if (e.key === 'ArrowLeft')  lbNav(-1);
    if (e.key === 'ArrowRight') lbNav(1);
    if (e.key === 'Escape')     closeLightbox();
});
</script>

</body>
</html>